'use client'; import { useEffect, useState } from 'react';
import { useRouter, usePathname } from 'next/navigation';
import Link from 'next/link';
import { FaSignOutAlt, FaFolderPlus, FaInbox, FaHome } from 'react-icons/fa'; export default function AdminLayout({ children }) { const router = useRouter(); const pathname = usePathname(); const [isClient, setIsClient] = useState(false); useEffect(() => { // eslint-disable-next-line react-hooks/exhaustive-deps setIsClient(true); // Simple client side protection - checking cookie existence // A more robust app would use Next.js Middleware to verify JWT if (!document.cookie.includes('admin_token=') && pathname !== '/admin/login') { router.push('/admin/login'); } }, [pathname, router]); const handleLogout = () => { document.cookie = 'admin_token=; path=/; expires=Thu, 01 Jan 1970 00:00:01 GMT;'; router.push('/admin/login'); }; if (!isClient) return null; if (pathname === '/admin/login') { return <div className="min-h-screen bg-[#ffffff] dark:bg-[#ffffff] flex flex-col">{children}</div>; } return ( <div className="min-h-screen bg-[#ffffff] dark:bg-[#ffffff] flex"> {/* Admin Sidebar */} <aside className="w-64 bg-[#ffffff] text-[#0066ff] flex flex-col hidden md:flex"> <div className="p-6 border-b border-[#0066ff]"> <Link href="/admin" className="text-xl font-bold tracking-tighter text-[#0066ff]"> Creator<span className="text-blue-500">Admin</span> </Link> </div> <nav className="flex-grow p-4 space-y-2 text-[#0066ff]"> <Link href="/admin" className={`flex items-center gap-3 p-3 rounded-lg hover:bg-[#ffffff] hover:text-[#0066ff] transition-colors ${pathname === '/admin' ? 'bg-[#ffffff] text-[#0066ff]' : ''}`}> <FaInbox /> Messages </Link> <Link href="/admin/projects" className={`flex items-center gap-3 p-3 rounded-lg hover:bg-[#ffffff] hover:text-[#0066ff] transition-colors ${pathname === '/admin/projects' ? 'bg-[#ffffff] text-[#0066ff]' : ''}`}> <FaFolderPlus /> Manage Projects </Link> <Link href="/" className="flex items-center gap-3 p-3 rounded-lg hover:bg-[#ffffff] hover:text-[#0066ff] transition-colors"> <FaHome /> Go to Website </Link> </nav> <div className="p-4 border-t border-[#0066ff]"> <button onClick={handleLogout} className="flex items-center gap-3 p-3 w-full rounded-lg text-red-400 hover:bg-[#ffffff] hover:text-red-300 transition-colors" > <FaSignOutAlt /> Logout </button> </div> </aside> {/* Main Content */} <main className="flex-1 overflow-y-auto"> {/* Mobile Header */} <div className="md:hidden bg-[#ffffff] border-b border-[#0066ff] p-4 flex justify-between items-center text-[#0066ff]"> <Link href="/admin" className="font-bold tracking-tighter">CreatorAdmin</Link> <button onClick={handleLogout} className="text-[#0066ff] p-1"><FaSignOutAlt size={20}/></button> </div> <div className="p-4 md:p-8"> {children} </div> </main> </div> );
}

"use client";
import { useState, useEffect } from "react";
import axios from "axios";
import { motion, AnimatePresence } from "framer-motion";
import { FaTrash, FaEdit, FaPlus, FaImage, FaVideo } from "react-icons/fa";
export default function AdminProjects() {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [uploading, setUploading] = useState(false);
  const initialForm = {
    title: "",
    description: "",
    category: "Graphics",
    mediaUrl: "",
    videoUrl: "",
  };
  const [formData, setFormData] = useState(initialForm);
  const [editingId, setEditingId] = useState(null);
  useEffect(() => {
    fetchProjects();
  }, []);
  const fetchProjects = async () => {
    try {
      const { data } = await axios.get("/api/projects");
      if (data.success) setProjects(data.data);
    } catch (error) {
      console.error("Error fetching projects", error);
    } finally {
      setLoading(false);
    }
  };
  const handleChange = (e) =>
    setFormData({ ...formData, [e.target.name]: e.target.value });
  const handleFileUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setUploading(true);
    const data = new FormData();
    data.append("file", file);
    try {
      const res = await axios.post("/api/upload", data);
      if (res.data.success) {
        setFormData((prev) => ({ ...prev, mediaUrl: res.data.url }));
      }
    } catch (err) {
      console.error("Upload failed", err);
      alert("File upload failed.");
    } finally {
      setUploading(false);
    }
  };
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingId) {
        await axios.put(`/api/projects/${editingId}`, formData);
      } else {
        await axios.post("/api/projects", formData);
      }
      setIsModalOpen(false);
      setFormData(initialForm);
      setEditingId(null);
      fetchProjects();
    } catch (err) {
      console.error("Error saving project", err);
      alert("Error saving project");
    }
  };
  const handleEdit = (project) => {
    setFormData(project);
    setEditingId(project._id);
    setIsModalOpen(true);
  };
  const handleDelete = async (id) => {
    if (confirm("Are you sure you want to delete this project?")) {
      try {
        await axios.delete(`/api/projects/${id}`);
        fetchProjects();
      } catch (err) {
        console.error("Delete failed", err);
      }
    }
  };
  const openNewModal = () => {
    setFormData(initialForm);
    setEditingId(null);
    setIsModalOpen(true);
  };
  if (loading)
    return (
      <div className="text-[#0066ff] animate-pulse">Loading projects...</div>
    );
  return (
    <div className="max-w-6xl mx-auto">
      {" "}
      <div className="flex justify-between items-center mb-8">
        {" "}
        <h1 className="text-3xl font-bold tracking-tighter text-[#0066ff] dark:text-[#0066ff]">
          Manage Projects
        </h1>{" "}
        <button
          onClick={openNewModal}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-[#0066ff] px-5 py-2.5 rounded-xl font-medium transition-colors shadow-sm"
        >
          {" "}
          <FaPlus /> Add New{" "}
        </button>{" "}
      </div>{" "}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {" "}
        {projects.map((project) => (
          <motion.div
            key={project._id}
            layout
            className="bg-[#ffffff] dark:bg-[#ffffff] border border-[#0066ff] dark:border-[#0066ff] rounded-2xl overflow-hidden shadow-sm"
          >
            {" "}
            <div className="aspect-video relative bg-[#ffffff] dark:bg-[#ffffff]">
              {" "}
              {project.mediaUrl ? (
                <img
                  src={project.mediaUrl}
                  alt={project.title}
                  className="w-full h-full object-cover"
                />
              ) : (
                <div className="flex h-full items-center justify-center text-[#0066ff]">
                  {" "}
                  <FaImage size={32} />{" "}
                </div>
              )}{" "}
              <div className="absolute top-3 left-3 bg-[#ffffff] backdrop-blur text-[#0066ff] text-xs px-2 py-1 rounded-md font-medium flex items-center gap-1">
                {" "}
                {project.category === "Videos" ? <FaVideo /> : <FaImage />}{" "}
                {project.category}{" "}
              </div>{" "}
            </div>{" "}
            <div className="p-5">
              {" "}
              <h3 className="text-lg font-bold text-[#0066ff] dark:text-[#0066ff] mb-1 truncate">
                {project.title}
              </h3>{" "}
              <p className="text-sm text-[#0066ff] dark:text-[#0066ff] line-clamp-2 mb-4">
                {project.description}
              </p>{" "}
              <div className="flex gap-2">
                {" "}
                <button
                  onClick={() => handleEdit(project)}
                  className="flex-1 flex justify-center items-center gap-2 py-2 bg-[#ffffff] dark:bg-[#ffffff] hover:bg-[#ffffff] dark:hover:bg-[#ffffff] text-[#0066ff] dark:text-[#0066ff] rounded-lg text-sm font-medium transition-colors"
                >
                  {" "}
                  <FaEdit /> Edit{" "}
                </button>{" "}
                <button
                  onClick={() => handleDelete(project._id)}
                  className="flex-1 flex justify-center items-center gap-2 py-2 bg-red-50 dark:bg-red-900/20 hover:bg-red-100 dark:hover:bg-red-900/40 text-red-600 dark:text-red-400 rounded-lg text-sm font-medium transition-colors"
                >
                  {" "}
                  <FaTrash /> Delete{" "}
                </button>{" "}
              </div>{" "}
            </div>{" "}
          </motion.div>
        ))}{" "}
      </div>{" "}
      {/* Project Modal */}{" "}
      <AnimatePresence>
        {" "}
        {isModalOpen && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center bg-[#ffffff] backdrop-blur-sm p-4">
            {" "}
            <motion.div
              initial={{ scale: 0.95, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.95, opacity: 0 }}
              className="bg-[#ffffff] dark:bg-[#ffffff] w-full max-w-2xl rounded-3xl p-6 md:p-8 overflow-y-auto max-h-[90vh] border border-[#0066ff] dark:border-[#0066ff] shadow-2xl"
            >
              {" "}
              <h2 className="text-2xl font-bold text-[#0066ff] dark:text-[#0066ff] mb-6">
                {" "}
                {editingId ? "Edit Project" : "Add New Project"}{" "}
              </h2>{" "}
              <form onSubmit={handleSubmit} className="space-y-5">
                {" "}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                  {" "}
                  <div>
                    {" "}
                    <label className="block text-sm font-medium text-[#0066ff] dark:text-[#0066ff] mb-2">
                      Title
                    </label>{" "}
                    <input
                      required
                      name="title"
                      value={formData.title}
                      onChange={handleChange}
                      className="w-full px-4 py-3 rounded-xl bg-[#ffffff] dark:bg-[#ffffff] border border-[#0066ff] dark:border-[#0066ff] focus:ring-2 focus:ring-blue-500"
                    />{" "}
                  </div>{" "}
                  <div>
                    {" "}
                    <label className="block text-sm font-medium text-[#0066ff] dark:text-[#0066ff] mb-2">
                      Category
                    </label>{" "}
                    <select
                      name="category"
                      value={formData.category}
                      onChange={handleChange}
                      className="w-full px-4 py-3 rounded-xl bg-[#ffffff] dark:bg-[#ffffff] border border-[#0066ff] dark:border-[#0066ff] focus:ring-2 focus:ring-blue-500"
                    >
                      {" "}
                      <option value="Graphics">Graphics</option>{" "}
                      <option value="Videos">Videos</option>{" "}
                    </select>{" "}
                  </div>{" "}
                </div>{" "}
                <div>
                  {" "}
                  <label className="block text-sm font-medium text-[#0066ff] dark:text-[#0066ff] mb-2">
                    Description
                  </label>{" "}
                  <textarea
                    required
                    name="description"
                    rows={4}
                    value={formData.description}
                    onChange={handleChange}
                    className="w-full px-4 py-3 rounded-xl bg-[#ffffff] dark:bg-[#ffffff] border border-[#0066ff] dark:border-[#0066ff] focus:ring-2 focus:ring-blue-500"
                  />{" "}
                </div>{" "}
                <div>
                  {" "}
                  <label className="block text-sm font-medium text-[#0066ff] dark:text-[#0066ff] mb-2">
                    Thumbnail Media
                  </label>{" "}
                  <div className="flex gap-4 items-center">
                    {" "}
                    <input
                      type="file"
                      accept="image/*,video/*"
                      onChange={handleFileUpload}
                      className="text-sm file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100"
                    />{" "}
                    {uploading && (
                      <span className="text-sm text-blue-500 animate-pulse">
                        Uploading...
                      </span>
                    )}{" "}
                  </div>{" "}
                  {formData.mediaUrl && (
                    <div className="mt-3 text-xs flex items-center gap-2 text-green-600 bg-green-50 p-2 rounded-lg truncate">
                      {" "}
                      ✓ Uploaded: {formData.mediaUrl}{" "}
                    </div>
                  )}{" "}
                </div>{" "}
                {formData.category === "Videos" && (
                  <div>
                    {" "}
                    <label className="block text-sm font-medium text-[#0066ff] dark:text-[#0066ff] mb-2">
                      Video Embed URL (e.g. YouTube/Vimeo)
                    </label>{" "}
                    <input
                      name="videoUrl"
                      value={formData.videoUrl}
                      onChange={handleChange}
                      placeholder="https://youtube.com/watch?v=..."
                      className="w-full px-4 py-3 rounded-xl bg-[#ffffff] dark:bg-[#ffffff] border border-[#0066ff] dark:border-[#0066ff] focus:ring-2 focus:ring-blue-500"
                    />{" "}
                  </div>
                )}{" "}
                <div className="pt-6 flex justify-end gap-3 border-t border-[#0066ff] dark:border-[#0066ff] mt-6">
                  {" "}
                  <button
                    type="button"
                    onClick={() => setIsModalOpen(false)}
                    className="px-6 py-3 rounded-xl font-medium text-[#0066ff] dark:text-[#0066ff] bg-[#ffffff] dark:bg-[#ffffff] hover:bg-[#ffffff] dark:hover:bg-[#ffffff] transition-colors"
                  >
                    {" "}
                    Cancel{" "}
                  </button>{" "}
                  <button
                    type="submit"
                    disabled={uploading}
                    className="px-6 py-3 rounded-xl font-bold text-[#0066ff] bg-blue-600 hover:bg-blue-700 transition-colors disabled:opacity-50"
                  >
                    {" "}
                    Save Project{" "}
                  </button>{" "}
                </div>{" "}
              </form>{" "}
            </motion.div>{" "}
          </div>
        )}{" "}
      </AnimatePresence>{" "}
    </div>
  );
}

import { NextResponse } from 'next/server';
import jwt from 'jsonwebtoken'; const ADMIN_USERNAME = process.env.ADMIN_USERNAME || 'admin';
const ADMIN_PASSWORD = process.env.ADMIN_PASSWORD || 'password';
const JWT_SECRET = process.env.JWT_SECRET || 'supersecretportfoliojwttoken'; export async function POST(req) { try { const { username, password } = await req.json(); if (username === ADMIN_USERNAME && password === ADMIN_PASSWORD) { const token = jwt.sign({ username }, JWT_SECRET, { expiresIn: '1d' }); const response = NextResponse.json({ success: true, message: 'Logged in successfully' }); response.cookies.set({ name: 'admin_token', value: token, httpOnly: true, secure: process.env.NODE_ENV === 'production', path: '/', maxAge: 60 * 60 * 24, // 1 day }); return response; } return NextResponse.json({ success: false, message: 'Invalid credentials' }, { status: 401 }); } catch (error) { return NextResponse.json({ success: false, message: error.message }, { status: 500 }); }
}

import { NextResponse } from 'next/server';
import dbConnect from '@/lib/mongodb';
import Project from '@/models/Project'; import fs from 'fs';
import path from 'path'; export async function GET() { try { let projects = []; try { await dbConnect(); const dbProjects = await Project.find({}).sort({ createdAt: -1 }); projects = dbProjects.map(p => p.toObject()); } catch (dbError) { console.warn('MongoDB connection failed, serving static files only.', dbError.message); } // Add static images from public/img try { const imgDir = path.join(process.cwd(), 'public', 'img'); if (fs.existsSync(imgDir)) { const files = fs.readdirSync(imgDir); const staticProjects = files .filter(file => file.match(/\.(jpg|jpeg|png|gif|webp)$/i)) .map((file, index) => ({ _id: `static-img-${index}`, title: path.basename(file, path.extname(file)), description: 'Graphic Design', category: 'Graphics', mediaUrl: `/img/${file}`, createdAt: new Date().toISOString() })); projects = [...projects, ...staticProjects]; } } catch (fsError) { console.error('Error reading static images:', fsError); } return NextResponse.json({ success: true, data: projects }); } catch (error) { return NextResponse.json({ success: false, error: error.message }, { status: 400 }); }
} export async function POST(req) { try { const body = await req.json(); await dbConnect(); const project = await Project.create(body); return NextResponse.json({ success: true, data: project }, { status: 201 }); } catch (error) { return NextResponse.json({ success: false, error: error.message }, { status: 400 }); }
}

import { NextResponse } from 'next/server';
import { writeFile } from 'fs/promises';
import { join } from 'path';
import { existsSync, mkdirSync } from 'fs'; export async function POST(req) { try { const data = await req.formData(); const file = data.get('file'); if (!file) { return NextResponse.json({ success: false, error: 'No file uploaded' }, { status: 400 }); } const bytes = await file.arrayBuffer(); const buffer = Buffer.from(bytes); const uploadsDir = join(process.cwd(), 'public/uploads'); // Create directory if it doesn't exist if (!existsSync(uploadsDir)) { mkdirSync(uploadsDir, { recursive: true }); } // Generate unique filename const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1e9); const filename = `${uniqueSuffix}-${file.name.replace(/\s+/g, '-')}`; const filepath = join(uploadsDir, filename); await writeFile(filepath, buffer); // Return the URL to be stored in the database const fileUrl = `/uploads/${filename}`; return NextResponse.json({ success: true, url: fileUrl }); } catch (error) { return NextResponse.json({ success: false, error: error.message }, { status: 500 }); }
}

'use client'; import { useState } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { FiMenu, FiX } from 'react-icons/fi';
import { motion, AnimatePresence } from 'framer-motion'; const NAV_LINKS = [ { label: 'Home', href: '/' }, { label: 'Portfolio', href: '/portfolio' }, { label: 'About', href: '/about' }, { label: 'Services', href: '/services' }, { label: 'Contact', href: '/contact' },
]; export default function Navbar() { const [isOpen, setIsOpen] = useState(false); const pathname = usePathname(); const toggleMenu = () => setIsOpen(!isOpen); if (pathname.startsWith('/admin')) { return null; // Don't show public navbar on admin pages } return ( <nav className="fixed top-0 w-full z-50 bg-[#ffffff] dark:bg-[#ffffff] backdrop-blur-md border-b border-[#0066ff] dark:border-[#0066ff] transition-colors duration-300"> <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8"> <div className="flex justify-between items-center h-20"> <Link href="/" className="text-2xl font-bold tracking-tighter text-[#0066ff] dark:text-[#0066ff]"> Creator<span className="text-blue-600 dark:text-blue-500">.</span> </Link> {/* Desktop Menu */} <div className="hidden md:flex space-x-8"> {NAV_LINKS.map((link) => ( <Link key={link.href} href={link.href} className={`relative text-sm font-medium transition-colors hover:text-blue-600 dark:hover:text-blue-400 ${ pathname === link.href ? 'text-blue-600 dark:text-blue-500' : 'text-[#0066ff] dark:text-[#0066ff]' }`} > {link.label} {pathname === link.href && ( <motion.div layoutId="navbar-indicator" className="absolute -bottom-2 left-0 right-0 h-0.5 bg-blue-600 dark:bg-blue-500" /> )} </Link> ))} </div> {/* Mobile Menu Button */} <div className="md:hidden flex items-center"> <button onClick={toggleMenu} className="text-[#0066ff] dark:text-[#0066ff] focus:outline-none p-2" aria-label="Toggle Menu" > {isOpen ? <FiX size={28} /> : <FiMenu size={28} />} </button> </div> </div> </div> {/* Mobile Menu Box */} <AnimatePresence> {isOpen && ( <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} exit={{ opacity: 0, height: 0 }} className="md:hidden bg-[#ffffff] dark:bg-[#ffffff] border-b border-[#0066ff] dark:border-[#0066ff]" > <div className="px-4 py-4 space-y-2"> {NAV_LINKS.map((link) => ( <Link key={link.href} href={link.href} onClick={() => setIsOpen(false)} className={`block px-3 py-2 rounded-md text-base font-medium ${ pathname === link.href ? 'bg-blue-50 dark:bg-[#ffffff] text-blue-600 dark:text-blue-500' : 'text-[#0066ff] dark:text-[#0066ff] hover:bg-[#ffffff] dark:hover:bg-[#ffffff]' }`} > {link.label} </Link> ))} </div> </motion.div> )} </AnimatePresence> </nav> );
}

"use client";
import { motion, AnimatePresence } from "framer-motion";
import { FiX } from "react-icons/fi";
export default function VideoModal({ isOpen, onClose, project }) {
  if (!isOpen || !project) return null;
  return (
    <AnimatePresence>
      {" "}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="fixed inset-0 z-[100] flex items-center justify-center bg-[#ffffff] backdrop-blur-sm p-4 md:p-8"
      >
        {" "}
        <motion.div
          initial={{ scale: 0.95, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          exit={{ scale: 0.95, opacity: 0 }}
          onClick={(e) => e.stopPropagation()}
          className="relative w-full max-w-5xl aspect-video bg-[#ffffff] rounded-2xl overflow-hidden shadow-2xl"
        >
          {" "}
          <button
            onClick={onClose}
            className="absolute top-4 right-4 z-10 p-2 bg-[#ffffff] hover:bg-[#ffffff] text-[#0066ff] rounded-full backdrop-blur-md transition-colors"
            aria-label="Close modal"
          >
            {" "}
            <FiX size={24} />{" "}
          </button>{" "}
          {project.category === "Videos" && project.videoUrl ? (
            <iframe
              src={
                project.videoUrl.replace("watch?v=", "embed/").split("&")[0] +
                "?autoplay=1"
              }
              title={project.title}
              className="w-full h-full border-0"
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
              allowFullScreen
            />
          ) : (
            <img
              src={project.mediaUrl}
              alt={project.title}
              className="w-full h-full object-contain"
            />
          )}{" "}
        </motion.div>{" "}
      </motion.div>{" "}
    </AnimatePresence>
  );
}
